/**
 * Generated fallback logo URL helpers shared by site data.
 * Logo images are generated by the website AI logo route at holocron.so.
 */

import type { HolocronConfig } from '../config.ts'

export type ResolvedLogo = HolocronConfig['logo'] & {
  /** True when the logo was AI-generated, not user-provided.
   *  Generated logos have opaque white backgrounds and need CSS blend-mode
   *  to appear transparent. */
  generated?: boolean
}

const DEFAULT_LOGO_TEXT = 'documentation'

export function normalizeGeneratedLogoText(text: string): string {
  const normalized = text.trim().replace(/\s+/g, ' ').toLowerCase()
  return normalized || DEFAULT_LOGO_TEXT
}

/** Returns a root-relative URL that hits the local ai-logo proxy route
 *  (registered in app-factory.tsx), avoiding cross-origin requests. */
export function getGeneratedLogoUrl(text: string): string {
  const normalized = normalizeGeneratedLogoText(text)
  return `/holocron-api/ai-logo/${encodeURIComponent(normalized)}.jpeg`
}

export function resolveLogo(logo: ResolvedLogo, siteName: string): ResolvedLogo {
  if (logo.light) return logo
  const generatedLogoUrl = getGeneratedLogoUrl(siteName)
  return {
    light: generatedLogoUrl,
    dark: generatedLogoUrl,
    href: logo.href,
    generated: true,
  }
}
